                            }

                            if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForResultHash] & RequiredBitForResultHash) == 0)
                            {
                                context.EvaluatedKeywordForProperty(false, 6, RequiredPropertyResultHashNotPresent, "resultHash"u8, "required"u8);
                            }
                            else
                            {
                                context.EvaluatedKeywordForProperty(true, 6, RequiredPropertyResultHashPresent, "resultHash"u8, "required"u8);
                            }

                            if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForResultId] & RequiredBitForResultId) == 0)
                            {
                                context.EvaluatedKeywordForProperty(false, 7, RequiredPropertyResultIdNotPresent, "resultId"u8, "required"u8);
                            }
                            else
                            {
                                context.EvaluatedKeywordForProperty(true, 7, RequiredPropertyResultIdPresent, "resultId"u8, "required"u8);
                            }

                            if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForResultKind] & RequiredBitForResultKind) == 0)
                            {
                                context.EvaluatedKeywordForProperty(false, 8, RequiredPropertyResultKindNotPresent, "resultKind"u8, "required"u8);
                            }
                            else
                            {
                                context.EvaluatedKeywordForProperty(true, 8, RequiredPropertyResultKindPresent, "resultKind"u8, "required"u8);
                            }

                            if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForUnresolvedOpenItemCount] & RequiredBitForUnresolvedOpenItemCount) == 0)
                            {
                                context.EvaluatedKeywordForProperty(false, 9, RequiredPropertyUnresolvedOpenItemCountNotPresent, "unresolvedOpenItemCount"u8, "required"u8);
                            }
                            else
                            {
                                context.EvaluatedKeywordForProperty(true, 9, RequiredPropertyUnresolvedOpenItemCountPresent, "unresolvedOpenItemCount"u8, "required"u8);
                            }
                        }
                    }
                }

                internal static bool Evaluate(
                    IJsonDocument parentDocument,
                    int parentIndex,
                    IJsonSchemaResultsCollector? resultsCollector = null)
                {
                    JsonSchemaContext context = JsonSchemaContext.BeginContext(
                    parentDocument,
                    parentIndex,
                    usingEvaluatedItems: false,
                    usingEvaluatedProperties: true,
                    resultsCollector: resultsCollector);
                    try
                    {
                        Evaluate(parentDocument, parentIndex, ref context);
                        context.EndContext();
                        return context.IsMatch;
                    }
                    finally
                    {
                        context.Dispose();
                    }
                }

                /// <summary>
                /// Push the current context as a child context for schema evaluation.
                /// </summary>
                /// <typeparam name="TContext">The type of the context to be passed to the path providers.</typeparam>
                /// <param name="parentDocument">The parent document of the instance for which to push the child context.</param>
                /// <param name="parentDocumentIndex">The index in the parent document of the instance for which to push the child context.</param>
                /// <param name="context">The current evaluation context.</param>
                /// <param name="providerContext">The context to be passed to the path providers.</param>
                /// <param name="schemaEvaluationPath">The (optional) path to the schema being evaluated in the child context.</param>
                /// <param name="documentEvaluationPath">The (optional) path in the document being evaluated in the child context.</param>
                /// <returns>The child context.</returns>
